// Normalize Web3Forms payload to standard lead format
const body = $input.first().json;

// Web3Forms sends fields as top-level keys
const lead = {
  name: body.name || body.full_name || '',
  phone: body.phone || body.telephone || '',
  email: body.email || '',
  address: body.address || '',
  service: body.service || body.service_type || '',
  timeline: body.timeline || '',
  notes: body.notes || body.message || '',
  city: body.city || extractCity(body.address || ''),
  source: 'landing-page-form',
  form_page: body.subject || '',
  timestamp: new Date().toLocaleString('en-US', { timeZone: 'America/New_York' })
};

function extractCity(address) {
  const cities = ['Tampa','St. Petersburg','Clearwater','Brandon','Largo','Riverview',
    'Wesley Chapel','Lutz','New Tampa','Palm Harbor','Dunedin','Safety Harbor',
    'Land O Lakes','Apollo Beach','Sun City Center'];
  for (const city of cities) {
    if (address.toLowerCase().includes(city.toLowerCase())) return city;
  }
  return 'Tampa Bay';
}

// Score the lead
let score = 0;
const tl = lead.timeline.toLowerCase();
if (tl.includes('asap')) score += 40;
else if (tl.includes('month') && !tl.includes('3')) score += 25;
else if (tl.includes('1-3')) score += 10;

const svc = lead.service.toLowerCase();
if (svc.includes('hurricane') || svc.includes('impact')) score += 30;
else if (svc.includes('full') || svc.includes('whole')) score += 30;
else if (svc.includes('energy')) score += 20;
else if (svc.includes('commercial')) score += 25;
else if (svc.includes('single')) score += 10;
else if (svc.includes('repair')) score += 5;
else score += 15;

if (lead.phone.length > 7) score += 15;
if (lead.email.includes('@')) score += 10;
if (lead.address.length > 3) score += 5;
score += 5; // form source bonus

const rating = score >= 70 ? 'HOT' : score >= 40 ? 'WARM' : 'COLD';

return [{ json: { ...lead, score, rating } }];
